'use client';

import { mockProjects } from "@/lib/mock-data";
import { notFound, useParams } from "next/navigation";
import { ProjectStatusBadge } from "@/components/project-status-badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Briefcase, Calendar, Users, ArrowLeft, Pencil } from "lucide-react";
import Link from "next/link";
import * as React from 'react';

export default function ProjectDetailsPage() {
    const params = useParams();
    const projectId = params.id as string;
    const project = mockProjects.find((p) => p.id === projectId);

    if (!project) {
        notFound();
    }
    
    // In a real app, this would come from an auth context
    const isUserAdmin = true; 
    const parentRoute = isUserAdmin ? '/admin/projects' : '/dashboard';

    return (
        <div className="space-y-6">
            <div className="flex flex-wrap items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <Button variant="outline" size="icon" asChild>
                        <Link href={parentRoute}>
                            <ArrowLeft className="h-4 w-4" />
                        </Link>
                    </Button>
                    <div className="flex-grow">
                        <h1 className="text-3xl font-bold font-headline">{project.title}</h1>
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            por
                            <Avatar className="h-6 w-6">
                                <AvatarImage src={project.solicitante.avatarUrl} />
                                <AvatarFallback>
                                    {project.solicitante.name.charAt(0)}
                                </AvatarFallback>
                            </Avatar>
                            <span>{project.solicitante.name}</span>
                        </div>
                    </div>
                </div>
                 <div className="flex items-center gap-2">
                    {isUserAdmin && (
                         <Button asChild>
                            <Link href={`/projects/${project.id}/edit`}>
                                <Pencil className="mr-2 h-4 w-4" />
                                Editar proyecto
                            </Link>
                        </Button>
                    )}
                 </div>
            </div>

            <div className="grid md:grid-cols-3 gap-6">
                <div className="md:col-span-2 space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle>Resumen del proyecto</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <p className="text-muted-foreground">{project.abstract}</p>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader>
                            <CardTitle>Estudiantes inscritos ({project.studentsEnrolled.length}/{project.studentLimit})</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-4">
                                {project.studentsEnrolled.length > 0 ? project.studentsEnrolled.map((student) => (
                                    <div key={student.id} className="flex items-center gap-3">
                                        <Avatar>
                                            <AvatarImage src={student.avatarUrl} />
                                            <AvatarFallback>{student.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                                        </Avatar>
                                        <div>
                                            <div className="font-medium">{student.name}</div>
                                            <div className="text-sm text-muted-foreground">{student.email}</div>
                                        </div>
                                    </div>
                                )) : (
                                    <p className="text-sm text-muted-foreground">Aún no hay estudiantes inscritos.</p>
                                )}
                            </div>
                        </CardContent>
                    </Card>
                </div>
                <div className="space-y-6">
                    <Card>
                        <CardHeader className="pb-2">
                           <ProjectStatusBadge status={project.status} />
                        </CardHeader>
                        <CardContent className="space-y-4 pt-4">
                           <div className="flex items-center gap-2 text-muted-foreground">
                                <Briefcase className="h-5 w-5" />
                                <span>{project.category}</span>
                            </div>
                            <div className="flex items-center gap-2 text-muted-foreground">
                                <Calendar className="h-5 w-5" />
                                <span>{project.timeline}</span>
                            </div>
                            <div className="flex items-center gap-2 text-muted-foreground">
                                <Users className="h-5 w-5" />
                                <span>{project.studentLimit} Estudiantes</span>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader>
                            <CardTitle>Habilidades requeridas</CardTitle>
                        </CardHeader>
                        <CardContent className="flex flex-wrap gap-2">
                            {project.requiredSkills.map((skill) => (
                                <Badge key={skill} variant="secondary">{skill}</Badge>
                            ))}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}
